const configs = createAdapterConfig([
  { entry: 'src/index.ts', outfile: 'dist/index' },
  { entry: 'src/bin.ts', outfile: 'dist/bin' },
])

// Add shebang banner to the bin entry configs
for (const config of configs) {
  if (config.entryPoints?.toString().includes('bin.ts')) {
    config.banner = { js: '#!/usr/bin/env node' }
  }
