### Step 7: `packages/generator-rest-client/src/generator.ts` -- Handler Implementation

This file contains the `onManifest` and `onGenerate` functions that satisfy the `Handler` interface from `@prisma/generator-helper`.

```typescript
import fs from 'node:fs'
import path from 'node:path'

import type { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { generateRestClient } from './generate'

export function onManifest(): GeneratorManifest {
  return {
    defaultOutput: './generated/rest-client',
    prettyName: 'Prisma REST Client',
  }
}

export async function onGenerate(options: GeneratorOptions): Promise<void> {
  const output = options.generator.output
  if (!output || !output.value) {
    throw new Error('No output directory specified for generator-rest-client')
  }

  const outputDir = output.fromEnvVar
    ? process.env[output.fromEnvVar] ?? output.value
    : output.value

  const baseUrl = options.generator.config.baseUrl as string | undefined

  const content = generateRestClient(options.dmmf, { baseUrl })

  fs.mkdirSync(outputDir, { recursive: true })
  fs.writeFileSync(path.join(outputDir, 'rest-client.ts'), content, 'utf-8')
}
```

Design decisions:
- **`onManifest`** returns a `defaultOutput` of `./generated/rest-client`. This is the path relative to the schema file that Prisma will use if the user does not specify `output` in their generator block.
- **`onGenerate`** resolves the output directory from `options.generator.output` (an `EnvValue` object). It does NOT use `parseEnvValue` from `@prisma/internals` to avoid that heavy dependency; instead it does the simple env resolution inline.
- The generator supports a `baseUrl` config option that can be set in the schema: `config { baseUrl = "https://api.example.com" }`.
- Uses synchronous `fs` operations since the output is a single small file and simplicity trumps parallelism here.

### Step 8: `packages/generator-rest-client/src/generate.ts` -- Core Generation Logic

This is the pure function that transforms DMMF into a TypeScript string. It is separated from the handler to make it independently testable.

```typescript
import type * as DMMF from '@prisma/dmmf'

import {
  generateEnumDeclaration,
  generateModelCreateInput,
  generateModelInterface,
  generateModelUpdateInput,
  generateRestClientClass,
  PREAMBLE,
} from './template'

export interface GenerateOptions {
  baseUrl?: string
}

export function generateRestClient(
  dmmf: DMMF.Document,
  options: GenerateOptions = {},
): string {
  const lines: string[] = [PREAMBLE]

  // Generate enum types
  for (const enumType of dmmf.datamodel.enums) {
    lines.push(generateEnumDeclaration(enumType))
    lines.push('')
  }

  // Generate model interfaces, create inputs, and update inputs
  for (const model of dmmf.datamodel.models) {
    lines.push(generateModelInterface(model, dmmf.datamodel.enums))
    lines.push('')
    lines.push(generateModelCreateInput(model, dmmf.datamodel.enums))
    lines.push('')
    lines.push(generateModelUpdateInput(model, dmmf.datamodel.enums))
    lines.push('')
  }

  // Generate the REST client class
  lines.push(
    generateRestClientClass(dmmf.datamodel.models, options.baseUrl),
  )

  return lines.join('\n')
}
```

### Step 9: `packages/generator-rest-client/src/template.ts` -- String Template Helpers

This is the most substantial file. It contains all the code generation logic.

**Scalar type mapping:**

```typescript
export type PrismaScalarType =
  | 'String' | 'Boolean' | 'Int' | 'Float' | 'Decimal'
  | 'DateTime' | 'Json' | 'BigInt' | 'Bytes'

export function mapScalarType(prismaType: string): string {
  switch (prismaType) {
    case 'String':    return 'string'
    case 'Boolean':   return 'boolean'
    case 'Int':       return 'number'
    case 'Float':     return 'number'
    case 'Decimal':   return 'string'  // Decimal is serialized as string in JSON
    case 'DateTime':  return 'string'  // ISO 8601 string in REST APIs
    case 'Json':      return 'unknown' // or JsonValue
    case 'BigInt':    return 'string'  // BigInt cannot be serialized as JSON number
    case 'Bytes':     return 'string'  // Base64-encoded
    default:          return prismaType // enum name or unknown model reference
  }
}
```

Design rationale for type mapping:
- `Decimal` -> `string`: JSON has no decimal type; the REST API will serialize decimals as strings to preserve precision.
- `DateTime` -> `string`: REST APIs transmit dates as ISO 8601 strings.
- `BigInt` -> `string`: JavaScript's `JSON.stringify` cannot handle BigInt; REST APIs serialize these as strings.
- `Bytes` -> `string`: Binary data is Base64-encoded for transport.
- `Json` -> `unknown`: The most accurate type since JSON can be anything.
- Default case handles enums by passing through their name (which will be a generated enum/type).

**Preamble:**
```typescript
export const PREAMBLE = `// This file was auto-generated by @prisma/generator-rest-client
// Do not edit this file manually.
/* eslint-disable */

`
```

**Enum generation:**
```typescript
export function generateEnumDeclaration(enumType: DMMF.DatamodelEnum): string {
  const values = enumType.values.map((v) => `  ${v.name} = '${v.name}'`).join(',\n')
  return `export enum ${enumType.name} {\n${values}\n}`
}
```

**Interface generation** (for the full model type returned from the API):

```typescript
function resolveFieldType(field: DMMF.Field, enums: readonly DMMF.DatamodelEnum[]): string {
  const isEnum = enums.some((e) => e.name === field.type)
  const baseType = isEnum ? field.type : mapScalarType(field.type)
  const arrayType = field.isList ? `${baseType}[]` : baseType
  return field.isRequired ? arrayType : `${arrayType} | null`
}

export function generateModelInterface(
  model: DMMF.Model,
  enums: readonly DMMF.DatamodelEnum[],
): string {
  const scalarFields = model.fields.filter(
    (f) => f.kind === 'scalar' || f.kind === 'enum',
  )
  const lines = scalarFields.map((field) => {
    const tsType = resolveFieldType(field, enums)
    return `  ${field.name}: ${tsType}`
  })
  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}
```

Key design decision: Only `scalar` and `enum` fields are included. Relation fields (`kind === 'object'`) are excluded because the REST API transfers flat JSON, not nested objects. If relation inclusion were desired, it would require a separate design discussion about nested resource URLs.

**Create input generation** (excludes ID fields that have defaults, and `isReadOnly` / `isUpdatedAt` fields):

```typescript
export function generateModelCreateInput(
  model: DMMF.Model,
  enums: readonly DMMF.DatamodelEnum[],
): string {
  const scalarFields = model.fields.filter(
    (f) => (f.kind === 'scalar' || f.kind === 'enum') && !f.isReadOnly && !f.isUpdatedAt,
  )

  const lines = scalarFields.map((field) => {
    // Fields with defaults or auto-generated IDs are optional on create
    const optional = field.hasDefaultValue || field.isId ? '?' : ''
    const required = field.isRequired && !field.hasDefaultValue && !field.isId
    const tsType = resolveFieldType(field, enums)
    // For create: fields without defaults that are required stay required
    // Fields with defaults or isId become optional
    return `  ${field.name}${optional ? '?' : ''}: ${tsType}`
  })

  return `export interface ${model.name}CreateInput {\n${lines.join('\n')}\n}`
}
```

**Update input generation** (all fields optional via Partial-like semantics):

```typescript
export function generateModelUpdateInput(
  model: DMMF.Model,
  enums: readonly DMMF.DatamodelEnum[],
): string {
  const scalarFields = model.fields.filter(
    (f) => (f.kind === 'scalar' || f.kind === 'enum') && !f.isReadOnly && !f.isUpdatedAt && !f.isId,
  )

  const lines = scalarFields.map((field) => {
    const tsType = resolveFieldType(field, enums)
    return `  ${field.name}?: ${tsType}`
  })

  return `export interface ${model.name}UpdateInput {\n${lines.join('\n')}\n}`
}
```

**REST client class generation:**

This is the most complex template. It generates a class with methods for each model.

```typescript
export function generateRestClientClass(
  models: readonly DMMF.Model[],
  baseUrl?: string,
): string {
  const defaultUrl = baseUrl ? `'${baseUrl}'` : `'http://localhost:3000'`

  const methodBlocks = models.map((model) => generateModelMethods(model))

  return `export class PrismaRestClient {
  private baseUrl: string
  private headers: Record<string, string>

  constructor(options: { baseUrl?: string; headers?: Record<string, string> } = {}) {
    this.baseUrl = options.baseUrl ?? ${defaultUrl}
    this.headers = {
      'Content-Type': 'application/json',
      ...options.headers,
    }
  }

  private async request<T>(path: string, options: RequestInit = {}): Promise<T> {
    const response = await fetch(\`\${this.baseUrl}\${path}\`, {
      ...options,
      headers: { ...this.headers, ...options.headers as Record<string, string> },
    })
    if (!response.ok) {
      throw new Error(\`REST client error: \${response.status} \${response.statusText}\`)
    }
    return response.json() as Promise<T>
  }

${methodBlocks.join('\n\n')}
}`
}
```

**Per-model CRUD method generation:**

```typescript
function getIdInfo(model: DMMF.Model): { fields: string[]; paramType: string; pathSuffix: string } {
  // Case 1: Composite primary key via @@id
  if (model.primaryKey && model.primaryKey.fields.length > 0) {
    const fields = [...model.primaryKey.fields]
    // For composite keys, the identifier parameter is an object
    const paramType = `{ ${fields.map((f) => {
      const field = model.fields.find((mf) => mf.name === f)
      const tsType = field ? mapScalarType(field.type) : 'string'
      return `${f}: ${tsType}`
    }).join('; ')} }`
    // URL encoding: serialize composite key fields as path segments
    const pathParts = fields.map((f) => `\${encodeURIComponent(String(id.${f}))}`)
    const pathSuffix = pathParts.join('/')
    return { fields, paramType, pathSuffix }
  }

  // Case 2: Single @id field
  const idField = model.fields.find((f) => f.isId)
  if (idField) {
    const tsType = mapScalarType(idField.type)
    return {
      fields: [idField.name],
      paramType: tsType,
      pathSuffix: `\${encodeURIComponent(String(id))}`,
    }
  }

  // Case 3: @unique field as fallback (first unique scalar field)
  const uniqueField = model.fields.find((f) => f.isUnique && f.kind === 'scalar')
  if (uniqueField) {
    const tsType = mapScalarType(uniqueField.type)
    return {
      fields: [uniqueField.name],
      paramType: tsType,
      pathSuffix: `\${encodeURIComponent(String(id))}`,
    }
  }

  // No identifier found; skip findUnique/update/delete
  return { fields: [], paramType: 'never', pathSuffix: '' }
}

function toUrlSegment(name: string): string {
  // Convert PascalCase model name to kebab-case URL segment
  return name
    .replace(/([a-z0-9])([A-Z])/g, '$1-$2')
    .replace(/([A-Z])([A-Z][a-z])/g, '$1-$2')
    .toLowerCase()
}

function generateModelMethods(model: DMMF.Model): string {
  const name = model.name
  const urlSegment = toUrlSegment(name)
  const idInfo = getIdInfo(model)
  const hasId = idInfo.fields.length > 0

  const methods: string[] = []

  // findMany
  methods.push(`  async ${lowerFirst(name)}FindMany(): Promise<${name}[]> {
    return this.request<${name}[]>('/${urlSegment}')
  }`)

  // findUnique (only if model has an identifier)
  if (hasId) {
    methods.push(`  async ${lowerFirst(name)}FindUnique(id: ${idInfo.paramType}): Promise<${name}> {
    return this.request<${name}>(\`/${urlSegment}/${idInfo.pathSuffix}\`)
  }`)
  }

  // create
  methods.push(`  async ${lowerFirst(name)}Create(data: ${name}CreateInput): Promise<${name}> {
    return this.request<${name}>('/${urlSegment}', {
      method: 'POST',
      body: JSON.stringify(data),
    })
  }`)

  // update (only if model has an identifier)
  if (hasId) {
    methods.push(`  async ${lowerFirst(name)}Update(id: ${idInfo.paramType}, data: ${name}UpdateInput): Promise<${name}> {
    return this.request<${name}>(\`/${urlSegment}/${idInfo.pathSuffix}\`, {
      method: 'PATCH',
      body: JSON.stringify(data),
    })
  }`)
  }

  // delete (only if model has an identifier)
  if (hasId) {
    methods.push(`  async ${lowerFirst(name)}Delete(id: ${idInfo.paramType}): Promise<${name}> {
    return this.request<${name}>(\`/${urlSegment}/${idInfo.pathSuffix}\`, {
      method: 'DELETE',
    })
  }`)
  }

  return methods.join('\n\n')
}

function lowerFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}
```

Design decisions for the REST client class:
1. **`fetch`-based**: Uses the global `fetch` (available in Node 18+ and all modern browsers), not `node-fetch` or `axios`. No extra dependency.
2. **Method naming**: `{modelName}{Operation}` with the model name lowercased first character, e.g., `userFindMany()`, `postCreate()`. This avoids name collisions and is consistent with the Prisma Client pattern.
3. **URL convention**: PascalCase model names are converted to kebab-case URL segments: `User` -> `/user`, `BlogPost` -> `/blog-post`.
4. **Composite primary keys**: For `@@id([fieldA, fieldB])`, the `findUnique`/`update`/`delete` methods accept an object `{ fieldA: type, fieldB: type }` and encode each field as a path segment: `/model/valueA/valueB`.
5. **Models without identifiers**: If a model has no `@id`, no `@@id`, and no `@unique` scalar field, then `findUnique`, `update`, and `delete` methods are skipped (only `findMany` and `create` are generated).
6. **HTTP methods**: GET for reads, POST for create, PATCH for update (partial), DELETE for delete.
7. **Constructor**: Accepts `baseUrl` (overridable at runtime) and `headers` (for auth tokens, etc.).

