/** Indent each line of `text` by `level * 2` spaces. */
export function indent(text: string, level: number): string {
  const pad = '  '.repeat(level)
  return text
    .split('\n')
    .map((line) => (line.trim() === '' ? '' : pad + line))
    .join('\n')
}

/** Join code blocks with blank-line separators. */
export function joinSections(sections: string[]): string {
  return sections.filter(Boolean).join('\n\n')
}

/** Wrap content in a TypeScript interface declaration. */
export function interfaceDecl(name: string, body: string): string {
  return `export interface ${name} {\n${indent(body, 1)}\n}`
}

/**
 * Map a Prisma scalar type to the corresponding TypeScript type.
 * Relation (object) and enum fields are handled by the caller.
 */
export function prismaScalarToTs(prismaType: string): string {
  switch (prismaType) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
    case 'Decimal':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'DateTime':
      return 'Date | string'
    case 'Json':
    case 'JSON':
      return 'unknown'
    case 'Bytes':
      return 'Buffer'
    default:
      return 'unknown'
  }
}

/** Build a file header comment. */
export function fileHeader(): string {
  return [
    '// ==========================================================',
    '// Generated by @prisma/generator-rest-client — DO NOT EDIT',
    '// ==========================================================',
    '',
  ].join('\n')
}

