export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value
  if (!outputDir) {
    throw new Error('@prisma/generator-rest-client: No output directory specified.')
  }

  const { models, enums } = options.dmmf.datamodel
  const sections: string[] = [fileHeader()]

  sections.push(generateBaseUrlConfig())
  sections.push(generateHelpers())

  for (const enumDef of enums) {
    sections.push(generateEnum(enumDef))
  }

  for (const model of models) {
    sections.push(generateModelInterface(model))
    sections.push(generateCreateInput(model))
    sections.push(generateUpdateInput(model))
    sections.push(generateWhereUniqueInput(model))
    sections.push(generateModelClient(model))
  }

  sections.push(generateRestClient(models))

  const output = joinSections(sections) + '\n'

  await fs.promises.mkdir(outputDir, { recursive: true })
  await fs.promises.writeFile(path.join(outputDir, 'rest-client.ts'), output)
}

function generateBaseUrlConfig(): string {
  return `export interface RestClientConfig {
  baseUrl: string
  headers?: Record<string, string>
}`
}

function generateHelpers(): string {
  return `async function request<T>(
  config: RestClientConfig,
  method: string,
  path: string,
  body?: unknown,
): Promise<T> {
  const url = \`\${config.baseUrl}\${path}\`
  const res = await fetch(url, {
    method,
    headers: {
      'Content-Type': 'application/json',
      ...config.headers,
    },
    body: body !== undefined ? JSON.stringify(body) : undefined,
  })
  if (!res.ok) {
    throw new Error(\`REST client request failed: \${method} \${path} — \${res.status} \${res.statusText}\`)
  }
  return res.json() as Promise<T>
}

function encodeQueryParams(params: Record<string, unknown>): string {
  const parts: string[] = []
  for (const [key, value] of Object.entries(params)) {
    if (value !== undefined) {
      parts.push(\`\${encodeURIComponent(key)}=\${encodeURIComponent(String(value))}\`)
    }
  }
  return parts.length > 0 ? \`?\${parts.join('&')}\` : ''
