import fs from 'node:fs'
import os from 'node:os'
import path from 'node:path'
import { afterEach, beforeEach, describe, expect, it } from 'vitest'

import type * as DMMF from '@prisma/dmmf'
import type { GeneratorOptions } from '@prisma/generator'

import { generate } from '../generator'

function makeDmmfDocument(models: DMMF.Model[], enums: DMMF.DatamodelEnum[] = []): DMMF.Document {
  return {
    datamodel: {
      models,
      enums,
      types: [],
      indexes: [],
    },
    schema: {
      inputObjectTypes: { prisma: [] },
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: { prisma: [] },
    },
    mappings: {
      modelOperations: [],
      otherOperations: { read: [], write: [] },
    },
  }
}

function makeGeneratorOptions(outputDir: string, dmmf: DMMF.Document): GeneratorOptions {
  return {
    generator: {
      name: 'restClient',
      output: { fromEnvVar: null, value: outputDir },
      provider: { fromEnvVar: null, value: 'prisma-generator-rest-client' },
      config: {},
      binaryTargets: [],
      previewFeatures: [],
      sourceFilePath: '/test/schema.prisma',
    },
    otherGenerators: [],
    schemaPath: '/test/schema.prisma',
    dmmf,
    datasources: [],
    datamodel: '',
    version: 'test',
  }
}

describe('generator', () => {
  let outputDir: string

  beforeEach(async () => {
    outputDir = await fs.promises.mkdtemp(path.join(os.tmpdir(), 'prisma-rest-gen-'))
  })

  afterEach(async () => {
    await fs.promises.rm(outputDir, { recursive: true, force: true })
  })

  it('generates rest-client.ts with model interfaces and CRUD classes', async () => {
    const userModel: DMMF.Model = {
      name: 'User',
      dbName: null,
      schema: null,
      fields: [
        {
          kind: 'scalar',
          name: 'id',
          isRequired: true,
          isList: false,
          isUnique: false,
          isId: true,
          isReadOnly: false,
          hasDefaultValue: true,
          type: 'Int',
          default: { name: 'autoincrement', args: [] },
        },
        {
          kind: 'scalar',
          name: 'email',
          isRequired: true,
          isList: false,
          isUnique: true,
          isId: false,
          isReadOnly: false,
          hasDefaultValue: false,
          type: 'String',
        },
        {
          kind: 'scalar',
          name: 'name',
          isRequired: false,
          isList: false,
          isUnique: false,
          isId: false,
          isReadOnly: false,
          hasDefaultValue: false,
          type: 'String',
        },
      ],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const dmmf = makeDmmfDocument([userModel])
    const options = makeGeneratorOptions(outputDir, dmmf)

    await generate(options)

    const outputFile = path.join(outputDir, 'rest-client.ts')
    expect(fs.existsSync(outputFile)).toBe(true)

    const content = await fs.promises.readFile(outputFile, 'utf-8')

    // Model interface
    expect(content).toContain('export interface User {')
    expect(content).toContain('id: number')
    expect(content).toContain('email: string')
    expect(content).toContain('name?: string | null')

    // Create input — id should be optional (autoincrement default)
    expect(content).toContain('export interface UserCreateInput {')
    expect(content).toMatch(/id\?: number/)

    // Update input — id should not appear
    expect(content).toContain('export interface UserUpdateInput {')
    expect(content).not.toMatch(/UserUpdateInput[\s\S]*?\bid\b.*?:/)

    // Where unique input
    expect(content).toContain('export interface UserWhereUniqueInput {')

    // Model client class
    expect(content).toContain('export class UserClient {')
    expect(content).toContain('findMany')
    expect(content).toContain('findUnique')
    expect(content).toContain('create')
    expect(content).toContain('update')
    expect(content).toContain('delete')

    // Top-level RestClient
    expect(content).toContain('export class RestClient {')
    expect(content).toContain('user: UserClient')
  })

  it('generates enums', async () => {
    const roleEnum: DMMF.DatamodelEnum = {
      name: 'Role',
      values: [
        { name: 'ADMIN', dbName: null },
        { name: 'USER', dbName: null },
      ],
    }

    const dmmf = makeDmmfDocument([], [roleEnum])
    const options = makeGeneratorOptions(outputDir, dmmf)

    await generate(options)

    const content = await fs.promises.readFile(path.join(outputDir, 'rest-client.ts'), 'utf-8')
    expect(content).toContain("export enum Role {")
    expect(content).toContain("ADMIN = 'ADMIN'")
    expect(content).toContain("USER = 'USER'")
  })

  it('handles multiple models', async () => {
    const models: DMMF.Model[] = [
      {
        name: 'Post',
        dbName: null,
        schema: null,
        fields: [
          {
            kind: 'scalar',
            name: 'id',
            isRequired: true,
            isList: false,
            isUnique: false,
            isId: true,
            isReadOnly: false,
            hasDefaultValue: true,
            type: 'String',
            default: { name: 'uuid', args: [] },
          },
          {
            kind: 'scalar',
            name: 'title',
            isRequired: true,
            isList: false,
            isUnique: false,
            isId: false,
            isReadOnly: false,
            hasDefaultValue: false,
            type: 'String',
          },
        ],
        uniqueFields: [],
        uniqueIndexes: [],
        primaryKey: null,
      },
      {
        name: 'Comment',
        dbName: null,
        schema: null,
        fields: [
          {
            kind: 'scalar',
            name: 'id',
            isRequired: true,
            isList: false,
            isUnique: false,
            isId: true,
            isReadOnly: false,
            hasDefaultValue: true,
            type: 'Int',
            default: { name: 'autoincrement', args: [] },
          },
          {
            kind: 'scalar',
            name: 'body',
            isRequired: true,
            isList: false,
            isUnique: false,
            isId: false,
            isReadOnly: false,
            hasDefaultValue: false,
            type: 'String',
          },
        ],
        uniqueFields: [],
        uniqueIndexes: [],
        primaryKey: null,
      },
    ]

    const dmmf = makeDmmfDocument(models)
    const options = makeGeneratorOptions(outputDir, dmmf)

    await generate(options)

    const content = await fs.promises.readFile(path.join(outputDir, 'rest-client.ts'), 'utf-8')

    expect(content).toContain('export class PostClient {')
    expect(content).toContain('export class CommentClient {')
    expect(content).toContain('export class RestClient {')
    expect(content).toContain('post: PostClient')
    expect(content).toContain('comment: CommentClient')
  })

  it('throws when no output directory is specified', async () => {
    const dmmf = makeDmmfDocument([])
    const options = makeGeneratorOptions(outputDir, dmmf)
    options.generator.output = null

    await expect(generate(options)).rejects.toThrow('No output directory specified')
  })
})

