import fs from 'node:fs'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'
import type { GeneratorOptions } from '@prisma/generator'

import { fileHeader, indent, interfaceDecl, joinSections, prismaScalarToTs } from './template'

/**
 * Main generation entry point.
 * Reads the DMMF from generator options and writes a typed REST API client
 * to the configured output directory.
 */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value
  if (!outputDir) {
    throw new Error('@prisma/generator-rest-client: No output directory specified.')
  }

  const { models, enums } = options.dmmf.datamodel
  const sections: string[] = [fileHeader()]

  sections.push(generateBaseUrlConfig())
  sections.push(generateHelpers())

  for (const enumDef of enums) {
    sections.push(generateEnum(enumDef))
  }

  for (const model of models) {
    sections.push(generateModelInterface(model))
    sections.push(generateCreateInput(model))
    sections.push(generateUpdateInput(model))
    sections.push(generateWhereUniqueInput(model))
    sections.push(generateModelClient(model))
  }

  sections.push(generateRestClient(models))

  const output = joinSections(sections) + '\n'

  await fs.promises.mkdir(outputDir, { recursive: true })
  await fs.promises.writeFile(path.join(outputDir, 'rest-client.ts'), output)
}

function generateBaseUrlConfig(): string {
  return `export interface RestClientConfig {
  baseUrl: string
  headers?: Record<string, string>
}`
}

function generateHelpers(): string {
  return `async function request<T>(
  config: RestClientConfig,
  method: string,
  path: string,
  body?: unknown,
): Promise<T> {
  const url = \`\${config.baseUrl}\${path}\`
  const res = await fetch(url, {
    method,
    headers: {
      'Content-Type': 'application/json',
      ...config.headers,
    },
    body: body !== undefined ? JSON.stringify(body) : undefined,
  })
  if (!res.ok) {
    throw new Error(\`REST client request failed: \${method} \${path} — \${res.status} \${res.statusText}\`)
  }
  return res.json() as Promise<T>
}

function encodeQueryParams(params: Record<string, unknown>): string {
  const parts: string[] = []
  for (const [key, value] of Object.entries(params)) {
    if (value !== undefined) {
      parts.push(\`\${encodeURIComponent(key)}=\${encodeURIComponent(String(value))}\`)
    }
  }
  return parts.length > 0 ? \`?\${parts.join('&')}\` : ''
}`
}

function resolveFieldType(field: DMMF.Field): string {
  if (field.kind === 'enum') {
    return field.type
  }

  if (field.kind === 'object') {
    // Relation fields reference another model by name
    return field.type
  }

  const tsType = prismaScalarToTs(field.type)
  if (field.isList) {
    return `${tsType}[]`
  }
  if (!field.isRequired) {
    return `${tsType} | null`
  }
  return tsType
}

function formatFieldType(field: DMMF.Field): string {
  const base = resolveFieldType(field)

  // For list relations, wrap in array
  if (field.kind === 'object' && field.isList) {
    return `${base}[]`
  }
  // Optional relation
  if (field.kind === 'object' && !field.isRequired) {
    return `${base} | null`
  }

  return base
}

function generateEnum(enumDef: DMMF.DatamodelEnum): string {
  const values = enumDef.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
  return `export enum ${enumDef.name} {\n${values}\n}`
}

function generateModelInterface(model: DMMF.Model): string {
  const lines = model.fields.map((field) => {
    const optional = !field.isRequired ? '?' : ''
    return `${field.name}${optional}: ${formatFieldType(field)}`
  })
  return interfaceDecl(model.name, lines.join('\n'))
}

function isScalarOrEnumField(field: DMMF.Field): boolean {
  return field.kind === 'scalar' || field.kind === 'enum'
}

function hasAutoDefault(field: DMMF.Field): boolean {
  if (!field.hasDefaultValue || field.default === undefined) return false

  if (typeof field.default === 'object' && field.default !== null && !Array.isArray(field.default)) {
    const def = field.default as DMMF.FieldDefault
    // autoincrement(), uuid(), cuid(), now(), etc. are auto-generated
    return ['autoincrement', 'uuid', 'cuid', 'now', 'auto', 'dbgenerated'].includes(def.name)
  }

  return false
}

function generateCreateInput(model: DMMF.Model): string {
  const fields = model.fields.filter(isScalarOrEnumField)
  const lines = fields.map((field) => {
    const isOptional = !field.isRequired || hasAutoDefault(field) || field.isUpdatedAt
    const optional = isOptional ? '?' : ''
    const baseType = resolveFieldType(field)
    const nullUnion = !field.isRequired && !isOptional ? ' | null' : ''
    return `${field.name}${optional}: ${baseType}${nullUnion}`
  })
  return interfaceDecl(`${model.name}CreateInput`, lines.join('\n'))
}

function generateUpdateInput(model: DMMF.Model): string {
  const fields = model.fields.filter(isScalarOrEnumField)
  const lines = fields
    .filter((f) => !f.isId)
    .map((field) => {
      const baseType = resolveFieldType(field)
      return `${field.name}?: ${baseType}${!field.isRequired ? ' | null' : ''}`
    })
  return interfaceDecl(`${model.name}UpdateInput`, lines.join('\n'))
}

function generateWhereUniqueInput(model: DMMF.Model): string {
  const idFields = model.fields.filter((f) => f.isId)
  const uniqueFields = model.fields.filter((f) => f.isUnique && !f.isId)

  const lines: string[] = []
  for (const field of [...idFields, ...uniqueFields]) {
    const tsType = resolveFieldType(field)
    lines.push(`${field.name}?: ${tsType}`)
  }

  if (lines.length === 0) {
    // Fallback: use all scalar fields as optional filters
    for (const field of model.fields.filter(isScalarOrEnumField)) {
      lines.push(`${field.name}?: ${resolveFieldType(field)}`)
    }
  }

  return interfaceDecl(`${model.name}WhereUniqueInput`, lines.join('\n'))
}

function modelEndpoint(model: DMMF.Model): string {
  return `/${model.name.toLowerCase()}`
}

function generateModelClient(model: DMMF.Model): string {
  const name = model.name
  const endpoint = modelEndpoint(model)

  const idField = model.fields.find((f) => f.isId) ?? model.fields.find((f) => f.isUnique)
  const idParam = idField ? idField.name : 'id'
  const idType = idField ? resolveFieldType(idField) : 'string'

  return `export class ${name}Client {
  #config: RestClientConfig

  constructor(config: RestClientConfig) {
    this.#config = config
  }

  /** Retrieve all ${name} records, with optional query parameters. */
  async findMany(params?: Record<string, unknown>): Promise<${name}[]> {
    const query = params ? encodeQueryParams(params) : ''
    return request<${name}[]>(this.#config, 'GET', '${endpoint}' + query)
  }

  /** Retrieve a single ${name} by its unique identifier. */
  async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {
    const id = where.${idParam}
    return request<${name} | null>(this.#config, 'GET', \`${endpoint}/\${id}\`)
  }

  /** Create a new ${name} record. */
  async create(data: ${name}CreateInput): Promise<${name}> {
    return request<${name}>(this.#config, 'POST', '${endpoint}', data)
  }

  /** Update an existing ${name} record by unique identifier. */
  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {
    const id = where.${idParam}
    return request<${name}>(this.#config, 'PATCH', \`${endpoint}/\${id}\`, data)
  }

  /** Delete a ${name} record by unique identifier. */
  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {
    const id = where.${idParam}
    return request<${name}>(this.#config, 'DELETE', \`${endpoint}/\${id}\`)
  }
}`
}

function generateRestClient(models: readonly DMMF.Model[]): string {
  const propLines = models.map((m) => `  ${m.name.charAt(0).toLowerCase() + m.name.slice(1)}: ${m.name}Client`)
  const assignLines = models.map(
    (m) =>
      `    this.${m.name.charAt(0).toLowerCase() + m.name.slice(1)} = new ${m.name}Client(config)`,
  )

  return `/**
 * Typed REST API client generated from the Prisma schema.
 *
 * @example
 * \`\`\`ts
 * const client = new RestClient({ baseUrl: 'http://localhost:3000/api' })
 * const users = await client.user.findMany()
 * \`\`\`
 */
export class RestClient {
${propLines.join('\n')}

  constructor(config: RestClientConfig) {
${assignLines.join('\n')}
  }
}`
}

